$path = [Environment]::GetEnvironmentVariable('Path', 'Machine'); $entries = $path -split ';' | Where-Object { $_.Trim() -ne '' }; Write-Host 'Total entries:' $entries.Count -ForegroundColor Cyan; Write-Host ''; $seen = @{}; $duplicates = 0; $invalid = 0; $valid = @(); foreach ($e in $entries) { $t = $e.Trim(); if ($seen.ContainsKey($t)) { Write-Host '[DUPLICATE]' $t -ForegroundColor Red; $duplicates++; } elseif (-not (Test-Path $t -ErrorAction SilentlyContinue)) { Write-Host '[INVALID]  ' $t -ForegroundColor Yellow; $invalid++; } else { $seen[$t] = $true; $valid += $t; } }; Write-Host ''; Write-Host 'Summary:' -ForegroundColor Yellow; Write-Host 'Duplicates:' $duplicates -ForegroundColor Red; Write-Host 'Invalid:' $invalid -ForegroundColor Yellow; Write-Host 'Valid:' $valid.Count -ForegroundColor Green; Write-Host ''; if ($duplicates -gt 0 -or $invalid -gt 0) { $ans = Read-Host 'Clean PATH? (Y/N)'; if ($ans -eq 'Y' -or $ans -eq 'y') { $newPath = $valid -join ';'; [Environment]::SetEnvironmentVariable('Path', $newPath, 'Machine'); Write-Host ''; Write-Host 'PATH cleaned! Removed' ($duplicates + $invalid) 'entries.' -ForegroundColor Green; } else { Write-Host 'Cancelled.' -ForegroundColor Yellow; } } else { Write-Host 'PATH is clean!' -ForegroundColor Green; }
